async function main() {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    let insertados = 0, actualizados = 0, errores = 0;
    for (const c of clientes) {
      try {
        const existe = await client.query(
          'SELECT id FROM yy_clients WHERE tenant_id=$1 AND empresa=$2 LIMIT 1',
          [TENANT_ID, c.codigo]
        );
        if (existe.rows.length > 0) {
          if (c.phone) {
            await client.query(
              'UPDATE yy_clients SET phone=$1, zona=$2, price_list_id=$3 WHERE id=$4',
              [c.phone, c.zona, PRICE_LIST_ID, existe.rows[0].id]
            );
            actualizados++;
          }
        } else {
          await client.query(
            `INSERT INTO yy_clients (tenant_id, nombre, empresa, phone, direccion, localidad, provincia, zona, price_list_id, condicion_pago)
             VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,'contado')`,
            [TENANT_ID, c.nombre, c.codigo, c.phone||null, c.direccion, c.localidad, c.provincia, c.zona, PRICE_LIST_ID]
          );
          insertados++;
        }
      } catch(e) { errores++; console.error('Error:', c.codigo, e.message); }
    }
    await client.query('COMMIT');
    console.log('Insertados:', insertados);
    console.log('Actualizados:', actualizados);
    console.log('Errores:', errores);
    console.log('TOTAL:', clientes.length);
  } catch(e) { await client.query('ROLLBACK'); console.error('ERROR:', e.message); }
  finally { client.release(); await pool.end(); }
}
main();
